{
  "guidedPractice": {
    "title": "Guided Practice: Winch Performance Calculation",
    "objective": "Calculate the work, power, and efficiency of a mechanical winch system following a structured multi-step process.",
    "retrievalTextLines": [
      "Formula 1: Work (J) = Force (N) × Distance (m)",
      "Formula 2: Power (W) = Work (J) ÷ Time (s)",
      "Formula 3: Efficiency (%) = (Power Output ÷ Power Input) × 100"
    ],
    "questionText": "An electric winch lifts a 600 N motor a vertical distance of 4 metres. The lift takes 12 seconds to complete. The electrical power supplied to the winch motor is 300 W. Calculate: 1) The Work Done (J), 2) The Mechanical Power Output (W), and 3) The Efficiency (%) of the system.",
    "answerGuidance": [
      "Work Done: 2,400 J (600N × 4m)",
      "Power Output: 200 W (2,400J ÷ 12s)",
      "Efficiency: 66.67% ((200W ÷ 300W) × 100)"
    ],
    "hint": "Follow the steps exactly like the worked example: find the total energy moved (Joules) before calculating the rate of movement (Watts)."
  },
  "practice": {
    "title": "Independent Practice: Lift System Analysis",
    "objective": "Independently solve for mechanical work, power, and efficiency in a practical installation scenario.",
    "retrievalTextLines": [
      "Remember: Power is the rate of doing work. Efficiency is always 'Useful Out' divided by 'Total In'.",
      "Units: Force is in Newtons, Work is in Joules, Power is in Watts."
    ],
    "questionText": "A site lift is used to move a 1,200 N distribution board up to a height of 3 metres. This operation takes 6 seconds. The motor driving the lift is rated at 800 W input power. Calculate the total Work Done, the useful Power Output, and the overall Efficiency of the lift.",
    "answerGuidance": [
      "Work Done: 3,600 J",
      "Power Output: 600 W",
      "Efficiency: 75%"
    ],
    "hint": "Start by calculating the Joules (Force x Distance). Then find the Watts (Joules / Seconds). Finally, compare your calculated Watts to the 800W input to find the efficiency."
  }
}

